// Configuration - Edit these values
const config = {
  workflowName: "Local LS", // Name of workflow to export
  n8nBaseUrl: "http://localhost:5678", // Try https:// if this fails
  includeCredentials: false,
  addTimestamp: false,
  exportDirectory: "/home/node/.n8n/workflows"
};

return [{ json: { config } }];

// Find target workflow - handle array response from n8n API
const config = $node['Config'].json.config;
const httpResponse = $input.first().json;
const targetName = config.workflowName;

// Handle different response structures
let workflows;
if (Array.isArray(httpResponse)) {
  workflows = httpResponse;
  console.log('Got workflow list as array');
} else if (httpResponse.data && Array.isArray(httpResponse.data)) {
  workflows = httpResponse.data;
  console.log('Got workflow list in data property');
} else {
  throw new Error('Unexpected response format from workflows API. Expected array, got: ' + typeof httpResponse);
}

console.log(`Searching for "${targetName}" among ${workflows.length} workflows`);

// Find matching workflow (case-insensitive)
const workflow = workflows.find(w => 
  w.name.toLowerCase() === targetName.toLowerCase()
);

if (!workflow) {
  const availableNames = workflows.map(w => w.name).join('\n  - ');
  throw new Error(`Workflow "${targetName}" not found.\n\nAvailable workflows:\n  - ${availableNames}`);
}

console.log(`✓ Found workflow: "${workflow.name}" (ID: ${workflow.id})`);

return [{ json: { config, workflowId: workflow.id, workflowName: workflow.name } }];

// Prepare export data - comprehensive debugging and handling
const config = $node['Config'].json.config;
const httpResponse = $input.first().json;

// Extensive debugging to understand the exact structure
console.log('=== DEBUGGING HTTP RESPONSE ===');
console.log('Response type:', typeof httpResponse);
console.log('Is array:', Array.isArray(httpResponse));
console.log('Response keys:', Object.keys(httpResponse || {}));
console.log('Full response structure:', JSON.stringify(httpResponse, null, 2));
console.log('================================');

// Handle the n8n API response which returns an array
let workflowData = null;

if (Array.isArray(httpResponse) && httpResponse.length > 0) {
  workflowData = httpResponse[0];
  console.log('✓ Extracted workflow from array position 0');
  console.log('Workflow ID:', workflowData?.id);
  console.log('Workflow name:', workflowData?.name);
} else if (httpResponse && httpResponse.data && Array.isArray(httpResponse.data) && httpResponse.data.length > 0) {
  workflowData = httpResponse.data[0];
  console.log('✓ Extracted workflow from data array position 0');
} else if (httpResponse && httpResponse.id) {
  workflowData = httpResponse;
  console.log('✓ Using direct response object');
} else {
  console.log('❌ Could not extract workflow data');
  console.log('Response type:', typeof httpResponse);
  console.log('Response is array:', Array.isArray(httpResponse));
  console.log('Response length:', Array.isArray(httpResponse) ? httpResponse.length : 'N/A');
  console.log('Response keys:', Object.keys(httpResponse || {}));
  throw new Error('Unable to extract workflow data from API response');
}

// Validate workflow data
if (!workflowData) {
  throw new Error('Workflow data is null or undefined');
}

if (!workflowData.id) {
  console.log('❌ Workflow data missing ID');
  console.log('Available fields:', Object.keys(workflowData));
  console.log('Workflow data:', JSON.stringify(workflowData, null, 2));
  throw new Error('Workflow data does not contain an ID field');
}

console.log('✓ Successfully extracted workflow:');
console.log('  - Name:', workflowData.name);
console.log('  - ID:', workflowData.id);
console.log('  - Nodes:', workflowData.nodes ? workflowData.nodes.length : 0);

// Create the export object
const exportData = {
  metadata: {
    exportedAt: new Date().toISOString(),
    exportedBy: "n8n-workflow-exporter",
    originalId: workflowData.id,
    originalName: workflowData.name,
    exportVersion: "1.0",
    versionId: workflowData.versionId || null
  },
  workflow: {
    name: workflowData.name,
    nodes: workflowData.nodes || [],
    connections: workflowData.connections || {},
    active: workflowData.active !== undefined ? workflowData.active : false,
    settings: workflowData.settings || {},
    versionId: workflowData.versionId || "1",
    tags: workflowData.tags || [],
    staticData: workflowData.staticData || null,
    meta: workflowData.meta || null,
    pinData: workflowData.pinData || {},
    triggerCount: workflowData.triggerCount || 0
  }
};

// Generate filename
const sanitized = workflowData.name.replace(/[^a-zA-Z0-9-_]/g, '_').toLowerCase();
const timestamp = config.addTimestamp ? `_${new Date().toISOString().slice(0, 19).replace(/[:.]/g, '-')}` : '';
const filename = `${sanitized}${timestamp}.json`;
const fullPath = `${config.exportDirectory}/${filename}`; //.replace('~', '$HOME');

console.log('✓ Export prepared successfully');
console.log('  - Filename:', filename);
console.log('  - Path:', fullPath);

return [{
  json: {
    exportData,
    filename,
    fullPath,
    workflowName: workflowData.name,
    workflowId: workflowData.id,
    nodeCount: workflowData.nodes ? workflowData.nodes.length : 0,
    exportSize: JSON.stringify(exportData).length
  }
}];

// Prepare file writing with smaller, safer approach
const data = $input.first().json;

// Create a smaller JSON string to test first
const jsonContent = JSON.stringify(data.exportData, null, 2);
const sizeKB = Math.round(jsonContent.length / 1024);

console.log('Preparing to write file:');
console.log('- Path:', data.fullPath);
console.log('- Size:', sizeKB, 'KB');
console.log('- Content length:', jsonContent.length, 'characters');

// Split into manageable chunks if too large
if (jsonContent.length > 50000) {
  console.log('⚠ Large file detected, this may take a moment...');
}

return [{
  json: {
    ...data,
    jsonContent: jsonContent,
    sizeKB: sizeKB
  }
}];

// Pass through data and prepare verification
const data = $input.first().json;
const previousData = $node['Prepare File Content'].json;

console.log('File write completed, preparing verification...');
console.log('Target file:', previousData.fullPath);

return [{
  json: {
    ...previousData,  // Get all data from the prepare step
    writeOutput: data.stdout || 'No output',
    writeError: data.stderr || 'No errors'
  }
}];

// Success report with detailed information
const data = $input.first().json;

console.log('='.repeat(60));
console.log('WORKFLOW EXPORT COMPLETED');
console.log('='.repeat(60));
console.log(`Workflow: ${data.workflowName}`);
console.log(`Workflow ID: ${data.workflowId}`);
console.log(`Node Count: ${data.nodeCount}`);
console.log(`File: ${data.filename}`);
console.log(`Path: ${data.fullPath}`);
console.log(`Size: ${(data.exportSize / 1024).toFixed(2)} KB`);
console.log('-'.repeat(60));
console.log('Export includes:');
console.log('✓ Complete workflow definition');
console.log('✓ All nodes and connections');
console.log('✓ Workflow settings and metadata');
console.log('✓ Static data and pin data');
console.log('✓ Export timestamp and version info');
console.log('='.repeat(60));

// Verify file was created
const fileExists = $input.first().json.stdout ? 'File created successfully' : 'File creation status unknown';
console.log(`Status: ${fileExists}`);

return [{
  json: {
    success: true,
    message: `Exported "${data.workflowName}" (${data.nodeCount} nodes) to ${data.filename}`,
    details: {
      workflowName: data.workflowName,
      workflowId: data.workflowId,
      nodeCount: data.nodeCount,
      filename: data.filename,
      path: data.fullPath,
      sizeKB: Math.round(data.exportSize / 1024 * 100) / 100,
      exportedAt: new Date().toISOString()
    }
  }
}];
